import{_ as t}from"./Menu.179edc93.js";import{u as n}from"./composables.96d18f89.js";import{_ as a}from"./noiseless-planche.7d168488.js";import{r as s,a as u,e,b as l,f as c,o as d}from"./entry.7b9f66e3.js";const p=""+new URL("noiseless-iv.ec5c5b7a.png",import.meta.url).href,m=""+new URL("page-accueil-noiseless-8.ddca9b2b.jpg",import.meta.url).href,v={class:"banniere"},f=c('<div class="margium-l marge-haute-l"><div class="espacium"><h1>Noiseless</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet de DUT 2 \xE0 l&#39;IUT de Lens<br> Septembre 2018 \xE0 avril 2019 </div><div class="colonne"><div class="projettitre">\xC9quipe</div><a href="https://alexandrelecoustre.netlify.app/" target="_blank">Alexandre Lecoustre</a>,<br><a href="https://fr.linkedin.com/in/lucie-septier" target="_blank">Lucie Septier</a>,<br><a href="https://fr.linkedin.com/in/ang%C3%A9line-dutoit-446293157" target="_blank">Ang\xE9line Dutoit</a></div><div class="colonne"><div class="projettitre">Outils</div> Premiere pro, Ronin S, Figma, Affinity Designer </div><div class="colonne"></div></div></div></div>',1),g=e("article",{class:"margium-l marge-haute-l marge-basse-l"},[e("div",{class:"espacium"},[e("div",{class:"coldroite"},[e("p",null,`Ce projet avait pour objectif de promouvoir le groupe de musique Noiseless \xE0 l'occasion de la sortie de leur premier album "Beautiful Ghost". Lors de ce projet, nous avons produit un clip, un site web, un logo, des photos issues d'un shooting et un dossier de presse. `),e("h2",null,"Identit\xE9 Visuelle"),e("img",{src:a,alt:"Planche de 18 dessins de logos pour le groupe Noiseless"}),e("p",null," Pour \xE9laborer l\u2019identit\xE9 du groupe, nous avons esquiss\xE9 18 logotypes, cette planche de dessin a \xE9t\xE9 soumise au vote des membres du groupe de rock. Les quatre esquisses s\xE9lectionn\xE9es, ont \xE9t\xE9 vectoris\xE9es, retravaill\xE9es, accompagn\xE9 de proposition de direction artistique diff\xE9rente. Le logotype 6 et sa direction artistique a fait l'unanimit\xE9. "),e("img",{src:p,alt:"identit\xE9 visuelle du groupe de rock : jeux typographique, couleurs et formes"}),e("h2",null,"Le clip vid\xE9o"),e("div",{class:"container"},[e("iframe",{class:"video",width:"720",height:"405",src:"https://www.youtube-nocookie.com/embed/17Lo9sJkBks",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})]),e("p",null," Nous avons d\u2019abord r\xE9alis\xE9 diff\xE9rents sc\xE9narios que nous avons d\xE9taill\xE9s au groupe de musique en exposant les contraintes techniques et logistiques que comprenait chacune d'entre elles. Apr\xE8s avoir fait plusieurs r\xE9unions et de nombreuses recherches, nous nous sommes positionn\xE9s sur un sc\xE9nario. Le concept \xE9tait de s\u2019inspirer des paroles qui parlaient d\u2019une rencontre amoureuse, et d\u2019en r\xE9aliser la fin, la rupture. Comme si la chanson racontait comment l\u2019histoire avait commenc\xE9. "),e("p",null,"Nous avons planifi\xE9 le tournage, organis\xE9 un casting, visit\xE9 plusieurs lieux de tournage, nous nous sommes form\xE9s au stabilisateur de cam\xE9ra (Ronin S). La d\xE9cision du lieu de tournage principal, c'est port\xE9 sur le Bistroquet, \xE0 Annoeullin, ce bar pr\xE9sentait des conditions favorables \xE0 notre tournage : suffisamment d'espace pour accueillir un public, un parcours suffisamment long pour notre plan s\xE9quence. "),e("p",null," Nous nous sommes attel\xE9s dans la r\xE9alisation d\u2019un story-board et d'un d\xE9coupage techniques en \xE9coutant la chanson pour rep\xE9rer quelle sc\xE8ne correspondait le mieux \xE0 un moment de la musique. La difficult\xE9 \xE9tait que nous ne pouvions pas pr\xE9voir \xE0 l\u2019avance la dur\xE9e des plans, nous avions pr\xE9vu de r\xE9aliser plusieurs plans de coupe pour combler les possibles vides entre les diff\xE9rentes sc\xE8nes clefs. "),e("h2",null,"Le Site web"),e("p",null,"L\u2019objectif du site \xE9tait de donner de la visibilit\xE9, faire d\xE9couvrir le groupe, d\u2019\xEAtre \xE0 l\u2019image du groupe et d'appuyer leur participation aux festivals et aux bars \xE0 concert de la r\xE9gion. Nous avons effectu\xE9 un benchmark UX sur diff\xE9rents sites de groupes de musique de rock afin de prendre les bonnes pratiques. Nous avons pris la d\xE9cision de mettre une partie \u2018\u2018espace pro\u2019\u2019 pour que les professionnels concern\xE9s puissent s\u2019informer sur le groupe : dossiers de presse, fiches techniques pour pr\xE9parer la sc\xE8ne, identit\xE9 visuelle. Nous avons \xE9galement pens\xE9 \xE0 la suite du projet. C'est-\xE0-dire, former le groupe pour la gestion \xE0 venir du site. "),e("img",{src:m,loading:"lazy",alt:"Page d'accueil du groupe de rock"})])])],-1),y={__name:"noiseless",setup(b){const i=s("Noiseless - Lucas Lacroix"),o=s("L\u2019objectif du site \xE9tait de donner de la visibilit\xE9, faire d\xE9couvrir le groupe, d\u2019\xEAtre \xE0 l\u2019image du groupe et d'appuyer leur participation aux festivals et aux bars \xE0 concert de la r\xE9gion.");return n({title:i,meta:[{name:"description",content:o}]}),(h,_)=>{const r=t;return d(),u("div",null,[e("div",v,[l(r),f]),g])}}};export{y as default};
